--
-- Table structure for table `notificaciones`
--

DROP TABLE IF EXISTS `notificaciones`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notificaciones` (
  `id_notificacion` int NOT NULL AUTO_INCREMENT,
  `id_usuario` int DEFAULT NULL,
  `id_destinatario` int NOT NULL DEFAULT '1',
  `tipo_destinatario` enum('usuario','tecnico') NOT NULL,
  `id_ticket` int DEFAULT NULL,
  `mensaje` text NOT NULL,
  `url_accion` varchar(500) DEFAULT NULL,
  `tipo` varchar(20) DEFAULT 'info',
  `titulo` varchar(200) NOT NULL DEFAULT 'Notificación',
  `leida` tinyint(1) DEFAULT '0',
  `fecha_creacion` datetime DEFAULT CURRENT_TIMESTAMP,
  `oculta` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id_notificacion`),
  KEY `idx_destinatario` (`id_destinatario`,`tipo_destinatario`,`leida`),
  KEY `id_ticket` (`id_ticket`),
  KEY `idx_notif_usuario` (`id_usuario`,`leida`),
  KEY `idx_notif_fecha` (`fecha_creacion`),
  CONSTRAINT `notificaciones_ibfk_1` FOREIGN KEY (`id_ticket`) REFERENCES `tickets` (`id_ticket`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=153 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `notificaciones`
--

LOCK TABLES `notificaciones` WRITE;
/*!40000 ALTER TABLE `notificaciones` DISABLE KEYS */;
