INSERT INTO `tickets` VALUES (1,'TKT-20260428-0001',4,NULL,7,2,'dejo de funcionar la impresora del pasillo AREA PROCUDADURIA','se acabo el toner el modelo de la impresora es dfggfssweff,si pueden venir a cambiarlo porfavor si nos urgue','Crítica','Cerrado',NULL,NULL,'2026-04-28 17:49:30','2026-04-28 18:07:54',NULL,NULL,NULL),(2,'TKT-20260428-0002',5,NULL,8,1,'no funciona el teléfono','NO RECIBO LAS LLAMADAS DE LA GENTE YA TENGO UN DIA ASI SIN RECIBIR LLAMADAS ENTRANTES','Alta','Cerrado',NULL,NULL,'2026-04-28 18:05:22','2026-04-28 18:06:01',NULL,NULL,NULL),(3,'TKT-20260430-0003',5,2,2,3,'no tengo internet en equipo','mi equipo no responde para cargar un sitio web ya revise la conexion y todo bien pero no se que onda','Alta','En Proceso',NULL,NULL,'2026-04-30 16:17:56','2026-04-30 19:24:56',NULL,NULL,NULL),(4,'TKT-20260430-0004',6,3,14,1,'paqueteria de office','intento descargar un formato para editarlo en word pero me pide que la abra en otra app y ya la descargue pero no me dejo editarla','Media','En Proceso',NULL,NULL,'2026-04-30 16:21:01','2026-04-30 23:10:36',NULL,NULL,NULL),(5,'TKT-20260430-0005',7,NULL,8,2,'no funciona el teléfono','no recibo las llamadas de los pacientes','Crítica','En Proceso',NULL,NULL,'2026-04-30 16:34:54','2026-04-30 16:45:42',NULL,NULL,NULL),(6,'TKT-20260430-0006',8,NULL,16,1,'no sirve la chequera','la computadora ahora no reconoce la chequera y antes si funciona sin problema','Crítica','En Proceso',NULL,NULL,'2026-04-30 16:36:36','2026-04-30 16:46:35',NULL,NULL,NULL),(7,'TKT-20260430-0007',9,6,4,2,'no prende mi equipo de computo','no reacciona mi equipo ya revise los cables de corriente y no es eso sigue fallando nose si puedan venir lo antes posible porque si me urgue','Media','En Proceso',NULL,NULL,'2026-04-30 16:39:06','2026-05-07 14:58:09',NULL,NULL,NULL),(8,'TKT-20260430-0008',10,NULL,7,3,'impresora dañada','hay que cambiar el tonner ya se acabo el que tenia es una cannos 48545,cunado puedan venir a cambiar se lo agradesariamos','Alta','Cerrado',NULL,NULL,'2026-04-30 16:41:41','2026-04-30 23:05:37',NULL,'2026-04-30 23:07:05',NULL),(9,'TKT-20260430-0009',11,NULL,16,1,'no sirven las camaras de la entrada','me acabo de percatar que las camaras del pasillo que te lleva al almacen  no estan funcionando para que le echen una revisada','Media','Cerrado','se reinicio su equipo y se aplico un analisis para descartar cuantos virus o app que este causando fallas, ','no descarguen app que no ucupen o que no saben para que sirve muchas de esas app traen virus y eso lentaliza los equipos.','2026-04-30 16:43:53','2026-04-30 19:22:12','2026-05-07 15:45:35','2026-05-07 15:46:07',NULL),(10,'TKT-20260506-0010',8,NULL,12,2,'no hay internet en el CIR','desde la mañana no tengo red','Media','Cerrado','se reseteo el sevidor','ninguna','2026-05-06 11:32:04','2026-05-06 12:14:14','2026-05-06 12:17:07','2026-05-06 12:17:37',NULL);
